let xstream = global.get("xstream")
let xalarms = global.get("xalarms")

const keys = (obj) => Object.keys(obj)
const values = (obj) => Object.values(obj)
const entries = (obj) => Object.entries(obj)

msg.payload.errors = []
let { xactive={},errors = [] } = msg.payload
// See On Start Too
const ipro_daikin_rules = context.iproDaikin || []
values(xalarms).forEach(xweb => {
    let { mac, devices, active_devices } = xweb
    let { stream_data } = xstream[mac];
    if (!stream_data) { errors.push({ reason: "stream_data missing", mac }); return; }
    let { stream } = stream_data;
    if (!stream) { errors.push({ reason: "stream missing", mac }); return; }
    let { data, acq } = stream;
    if (!data || !acq) { errors.push({ reason: "data missing", mac }); return; }

    // CUSTOME AREA
    entries(devices)
        .forEach(([devk, devv]) => {
            if (devv.alarm_rule !== "ac2025") return;
            if (!acq) return;
            // Cancel
            // devv.virtual_alarms || (devv.virtual_alarms = {});
            devv.active_alarms=[]
            let { active_alarms, virtual_alarms } = devv
            //custom
            let dev_data = data[devk] || {};
            dev_data && entries(devv.alarms).forEach(([pointId, point]) => {
                point.error = 0
                try {
                    point.value = dev_data[pointId];
                } catch {
                    point.error = 1
                    errors.push({ mac, devk, point })
                }

                let founded = ipro_daikin_rules.find(r => r.ids.includes(pointId));
                if (founded !== undefined) {
                    if (founded.ids[0] == pointId) {
                        let vid = founded.id
                        // Cancel
                        // virtual_alarms[vid] = founded.getAlarm(dev_data)
                        devv.alarms[vid] = founded.getAlarm(dev_data)
                        devv.alarms[vid].en = 1
                        devv.alarms[vid].value && active_alarms.push(vid)
                    }
                    point.en = 0;
                } else {
                    // Cancel
                    // virtual_alarms[pointId] = point
                    // virtual_alarms[pointId].value && (active.push(pointId))
                    point.value = data[devk][pointId];
                    point.en = 1;
                    point.value && active_alarms.push(pointId)
                }
            })
            // devv.active_alarms = active
            active_alarms.length && active_devices.push(devk);
        });
    !xactive[mac] && (active_devices.length > 0) && (xactive[mac] = !0)
})
context.count = context.count+1
let date = new Date().toLocaleString("en-UK", { timeZone: "Asia/Bangkok" }) 
node.status({ fill: "green", shape: "dot", text:`${date} (${context.count})` });
// DO NOT CHANGE OUTPUT
msg.payload = { xalarms, xactive, active_xwebs: keys(xactive), errors }
return msg

